firmware_template.source:
#include "mag_lis3mdl.h"
#include <Wire.h>
#include <Adafruit_LIS3MDL.h>
#include <math.h>
static Adafruit_LIS3MDL mag;
static float _x=0,_y=0,_z=0,_heading=0;
static unsigned long _last=0;
void lis3mdl_setup(){Wire.begin();if(!mag.begin_I2C()){Serial.println("[lis3mdl] Fail!");return;}mag.setPerformanceMode(LIS3MDL_MEDIUMMODE);mag.setOperationMode(LIS3MDL_CONTINUOUSMODE);mag.setDataRate(LIS3MDL_DATARATE_155_HZ);Serial.println("[lis3mdl] OK");}
void lis3mdl_loop(){if(millis()-_last<100)return;_last=millis();mag.read();_x=mag.x;_y=mag.y;_z=mag.z;_heading=atan2(_y,_x)*180.0/M_PI;if(_heading<0)_heading+=360;}
float lis3mdl_get_x(){return _x;}
float lis3mdl_get_y(){return _y;}
float lis3mdl_get_z(){return _z;}
float lis3mdl_get_heading(){return _heading;}
